<script setup lang="ts">
  const { modelValue, autofocus = false } = defineProps<{
    id?: string;
    label?: string;
    modelValue: unknown[] | Set<unknown> | boolean;
    autofocus?: boolean;
    after?: boolean;
  }>();

  const emit = defineEmits<{
    (
      event: 'update:modelValue',
      value: unknown[] | Set<unknown> | boolean,
    ): void;
  }>();

  let value = $computed({
    get: () => modelValue,
    set: v => emit('update:modelValue', v),
  });
</script>

<template>
  <Label
    :id="id"
    :label="label"
    class="transition-all flex items-center gap-2 h-10 py-2 cursor-pointer"
    :after="!after"
  >
    <template #label>
      <slot></slot>
    </template>

    <template #default="{ id: labelId }">
      <input
        :id="labelId"
        v-model="value"
        type="checkbox"
        :class="[
          'transition-all',
          'cursor-pointer',
          'self-center',
          'inline-block',
          'rounded',
          'text-current',
          'accent-current',
          'border-current',
          'focus:ring-0',
          'focus:ring-offset-0',
          'bg-transparent checked:bg-secondary',
        ]"
        :autofocus="autofocus"
      />
      <svg
        v-if="value"
        viewBox="0 0 16 16"
        class="fill-lower h-4 w-4 -ml-6"
      >
        <path
          d="M12.207 4.793a1 1 0 010 1.414l-5 5a1 1 0 01-1.414 0l-2-2a1 1 0 011.414-1.414L6.5 9.086l4.293-4.293a1 1 0 011.414 0z"
        />
      </svg>
    </template>
  </Label>
</template>

<style lang="scss" scoped>
  input[type='checkbox']:checked {
    @apply bg-none;
  }
</style>
