<script setup lang="ts">
  const storeSettings = await useStoreSettings();

  async function tryImport(file: File | null) {
    file && await storeSettings.import(file);
  }

  const log = $computed(() => JSON.stringify(storeSettings.log, undefined, 2));

  const release = import.meta.env.VITE_RELEASE;
</script>

<template>
  <NuxtLayout name="common">
    <template #header>
      <span class="text-xs font-mono lowercase text-gray-500">
        {{ release }}
      </span>
    </template>
    <template #default>
      <div class="pt-2 px-4 mb-2 grid grid-cols-1 gap-2">
        <Checkbox
          v-model="storeSettings.isDarkMode"
          label="Dark mode"
        />
        <div>
          <Button
            label="Export tasks"
            icon="fa6-solid:file-arrow-up"
            flat
            class="pl-0"
            @click="storeSettings.export()"
          />
        </div>
        <div>
          <Button
            class="relative pl-0"
            flat
          >
            <input
              class="absolute top-0 right-0 bottom-0 left-0 opacity-0"
              type="file"
              accept=".fa,.json"
              @change="e => tryImport((e.target as HTMLInputElement).files?.[0] ?? null).then(() => (e.target as HTMLInputElement).value = null as unknown as string)"
            />
            <Icon name="fa6-solid:file-arrow-down" />
            {{ 'Import tasks' }}
          </Button>
        </div>
        <Label
          v-if="storeSettings.log.length"
          label="Log"
          class="flex-col text-red-500"
        >
          <pre class="w-full">{{ log }}</pre>
        </Label>
      </div>
    </template>
  </NuxtLayout>
</template>

<style lang="scss"></style>
